from heapq import heappush, heappop
from collections import defaultdict

def shortest_path_with_waypoints(n, edges, start, end, waypoints):
    adj = defaultdict(list)
    for u, v, w in edges:
        adj[u].append((v, w))
    def dijkstra_all(src):
        dist = {}
        heap = [(0, src)]
        while heap:
            d, u = heappop(heap)
            if u in dist: continue
            dist[u] = d
            for v, w in adj.get(u, []):
                if v not in dist: heappush(heap, (d + w, v))
        return dist
    if not waypoints:
        d = dijkstra_all(start)
        r = d.get(end, float('inf'))
        return r if r < float('inf') else -1
    key_nodes = [start] + sorted(set(waypoints)) + [end]
    dist = {src: dijkstra_all(src) for src in key_nodes}
    wp = sorted(set(waypoints))
    m = len(wp)
    INF = float('inf')
    dp = [[INF]*m for _ in range(1<<m)]
    for i, w in enumerate(wp):
        if dist[start].get(w, INF) < INF: dp[1<<i][i] = dist[start][w]
    for mask in range(1, 1<<m):
        for last in range(m):
            if not (mask & (1<<last)) or dp[mask][last] == INF: continue
            for nxt in range(m):
                if mask & (1<<nxt): continue
                d = dist[wp[last]].get(wp[nxt], INF)
                if dp[mask][last] + d < dp[mask|(1<<nxt)][nxt]:
                    dp[mask|(1<<nxt)][nxt] = dp[mask][last] + d
    full = (1<<m)-1
    ans = INF
    for last in range(m):
        if dp[full][last] < INF:
            d = dist[wp[last]].get(end, INF)
            ans = min(ans, dp[full][last] + d)
    return ans if ans < INF else -1

from collections import defaultdict, deque

def count_longest_paths(n, edges, mod=10**9 + 7):
    adj = defaultdict(list)
    in_deg = [0] * n
    for u, v, w in edges:
        adj[u].append((v, w))
        in_deg[v] += 1
    queue = deque(i for i in range(n) if in_deg[i] == 0)
    topo = []
    while queue:
        u = queue.popleft()
        topo.append(u)
        for v, w in adj[u]:
            in_deg[v] -= 1
            if in_deg[v] == 0: queue.append(v)
    if len(topo) != n: return (-1, 0)
    in_deg2 = [0] * n
    for u, v, w in edges:
        in_deg2[v] += 1
    dist = [-1] * n
    cnt = [0] * n
    for i in range(n):
        if in_deg2[i] == 0:
            dist[i] = 0; cnt[i] = 1
    for u in topo:
        if dist[u] == -1: continue
        for v, w in adj[u]:
            nd = dist[u] + w
            if nd > dist[v]:
                dist[v] = nd; cnt[v] = cnt[u] % mod
            elif nd == dist[v]:
                cnt[v] = (cnt[v] + cnt[u]) % mod
    max_d = max(dist)
    if max_d <= 0:
        total = sum(1 for d in dist if d == 0) if max_d == 0 else 0
        return (max_d, total % mod)
    total = sum(cnt[i] for i in range(n) if dist[i] == max_d) % mod
    return (max_d, total)

class VersionedKVStore:
    def __init__(self):
        self._data = {}
        self._version = 0
        self._snapshots = {}
        self._next_snap = 0
    def put(self, key, value):
        self._version += 1
        if key not in self._data: self._data[key] = []
        self._data[key].append((self._version, value))
        return self._version
    def get(self, key, snap_id=None):
        if key not in self._data: return None
        history = self._data[key]
        if snap_id is not None:
            if snap_id not in self._snapshots: raise KeyError(f"Snapshot {snap_id} does not exist")
            max_ver = self._snapshots[snap_id]
            lo, hi = 0, len(history) - 1
            result = None
            while lo <= hi:
                mid = (lo + hi) // 2
                if history[mid][0] <= max_ver:
                    result = history[mid][1]; lo = mid + 1
                else: hi = mid - 1
            return result
        else:
            return history[-1][1] if history else None
    def delete(self, key):
        if key not in self._data or not self._data[key]: return False
        self._version += 1
        self._data[key].append((self._version, None))
        return True
    def snapshot(self):
        snap_id = self._next_snap; self._next_snap += 1
        self._snapshots[snap_id] = self._version
        return snap_id
    def rollback(self, snap_id):
        if snap_id not in self._snapshots: raise KeyError(f"Snapshot {snap_id} does not exist")
        target_ver = self._snapshots[snap_id]
        for key in self._data:
            self._data[key] = [(v, val) for v, val in self._data[key] if v <= target_ver]
        self._version = target_ver
        for s in [s for s, v in self._snapshots.items() if v > target_ver]: del self._snapshots[s]
    def keys(self, snap_id=None):
        result = []
        for key, history in self._data.items():
            if snap_id is not None:
                if snap_id not in self._snapshots: raise KeyError(f"Snapshot {snap_id} does not exist")
                max_ver = self._snapshots[snap_id]
                vals = [val for v, val in history if v <= max_ver]
                if vals and vals[-1] is not None: result.append(key)
            else:
                if history and history[-1][1] is not None: result.append(key)
        return sorted(result)

def eval_expr(expr):
    tokens, pos = tokenize(expr), [0]
    result = parse_additive(tokens, pos)
    if pos[0] != len(tokens):
        raise SyntaxError(f"Unexpected token at position {pos[0]}: {tokens[pos[0]]}")
    return result

def tokenize(expr):
    tokens, i = [], 0
    while i < len(expr):
        if expr[i].isspace():
            i += 1
        elif expr[i].isdigit() or expr[i] == '.':
            j = i
            while i < len(expr) and (expr[i].isdigit() or expr[i] == '.'):
                i += 1
            tokens.append(('NUM', float(expr[j:i]) if '.' in expr[j:i] else int(expr[j:i])))
        elif expr[i:i+2] == '**':
            tokens.append(('OP', '**'))
            i += 2
        elif expr[i] in '+-*/%':
            tokens.append(('OP', expr[i]))
            i += 1
        elif expr[i] == '(':
            tokens.append(('LPAREN',))
            i += 1
        elif expr[i] == ')':
            tokens.append(('RPAREN',))
            i += 1
        else:
            raise SyntaxError(f"Unexpected character: {expr[i]}")
    return tokens

def parse_additive(tokens, pos):
    left = parse_multiplicative(tokens, pos)
    while pos[0] < len(tokens) and tokens[pos[0]] == ('OP', '+') or (pos[0] < len(tokens) and tokens[pos[0]] == ('OP', '-')):
        op = tokens[pos[0]][1]
        pos[0] += 1
        right = parse_multiplicative(tokens, pos)
        left = left + right if op == '+' else left - right
    return left

def parse_multiplicative(tokens, pos):
    left = parse_power(tokens, pos)
    while pos[0] < len(tokens) and tokens[pos[0]][0] == 'OP' and tokens[pos[0]][1] in ('*', '/', '%'):
        op = tokens[pos[0]][1]
        pos[0] += 1
        right = parse_power(tokens, pos)
        if op == '*':
            left = left * right
        elif op == '/':
            if right == 0:
                raise ZeroDivisionError("division by zero")
            left = left / right
        else:
            if right == 0:
                raise ZeroDivisionError("modulo by zero")
            left = left % right
    return left

def parse_power(tokens, pos):
    base = parse_unary(tokens, pos)
    if pos[0] < len(tokens) and tokens[pos[0]] == ('OP', '**'):
        pos[0] += 1
        exp = parse_power(tokens, pos)
        return base ** exp
    return base

def parse_unary(tokens, pos):
    if pos[0] < len(tokens) and tokens[pos[0]] == ('OP', '-'):
        pos[0] += 1
        return -parse_unary(tokens, pos)
    if pos[0] < len(tokens) and tokens[pos[0]] == ('OP', '+'):
        pos[0] += 1
        return parse_unary(tokens, pos)
    return parse_primary(tokens, pos)

def parse_primary(tokens, pos):
    if pos[0] >= len(tokens):
        raise SyntaxError("Unexpected end of expression")
    tok = tokens[pos[0]]
    if tok[0] == 'NUM':
        pos[0] += 1
        return tok[1]
    if tok[0] == 'LPAREN':
        pos[0] += 1
        val = parse_additive(tokens, pos)
        if pos[0] >= len(tokens) or tokens[pos[0]][0] != 'RPAREN':
            raise SyntaxError("Missing closing parenthesis")
        pos[0] += 1
        return val
    raise SyntaxError(f"Unexpected token: {tok}")

import time, random
from functools import wraps

class CircuitBreakerOpen(Exception):
    pass

def resilient(max_retries=3, base_delay=0.01, max_delay=1.0, jitter=True,
              failure_threshold=5, recovery_timeout=10.0, half_open_max=1):
    def decorator(func):
        state = {'failures': 0, 'state': 'closed', 'last_failure_time': 0, 'half_open_calls': 0, 'call_log': []}
        @wraps(func)
        def wrapper(*args, **kwargs):
            now = time.monotonic()
            if state['state'] == 'open':
                if now - state['last_failure_time'] >= recovery_timeout:
                    state['state'] = 'half_open'; state['half_open_calls'] = 0
                else: raise CircuitBreakerOpen("open")
            if state['state'] == 'half_open':
                if state['half_open_calls'] >= half_open_max: raise CircuitBreakerOpen("half-open max")
                state['half_open_calls'] += 1
            last_exc = None
            for attempt in range(max_retries + 1):
                try:
                    result = func(*args, **kwargs)
                    state['call_log'].append((time.monotonic(), True))
                    if state['state'] == 'half_open': state['state'] = 'closed'; state['failures'] = 0
                    elif state['state'] == 'closed': state['failures'] = max(0, state['failures'] - 1)
                    return result
                except Exception as e:
                    last_exc = e
                    if attempt < max_retries:
                        delay = min(base_delay * (2 ** attempt), max_delay)
                        if jitter: delay *= random.uniform(0.5, 1.5)
                        time.sleep(delay)
            state['call_log'].append((time.monotonic(), False))
            state['failures'] += 1; state['last_failure_time'] = time.monotonic()
            if state['state'] == 'half_open': state['state'] = 'open'
            elif state['failures'] >= failure_threshold: state['state'] = 'open'
            raise last_exc
        wrapper.get_state = lambda: state['state']
        wrapper.get_failures = lambda: state['failures']
        wrapper.reset = lambda: state.update({'failures': 0, 'state': 'closed', 'half_open_calls': 0})
        wrapper.get_call_log = lambda: list(state['call_log'])
        return wrapper
    return decorator

