from collections import defaultdict, deque

def graph_analysis(n, edges):
    adj = defaultdict(set)
    for u, v in edges:
        adj[u].add(v)
        adj[v].add(u)

    visited = [False] * n
    components = []
    is_bipartite = True

    for start in range(n):
        if visited[start]:
            continue
        comp = []
        queue = deque([(start, 0)])
        visited[start] = True
        color = {start: 0}
        while queue:
            u, c = queue.popleft()
            comp.append(u)
            for v in adj[u]:
                if not visited[v]:
                    visited[v] = True
                    color[v] = 1 - c
                    queue.append((v, 1 - c))
                elif color[v] == c:
                    is_bipartite = False
        components.append(comp)

    sizes = sorted([len(c) for c in components], reverse=True)

    disc = [-1] * n
    low = [-1] * n
    bridges = []
    timer = [0]

    def dfs(u, parent):
        disc[u] = low[u] = timer[0]
        timer[0] += 1
        for v in adj[u]:
            if disc[v] == -1:
                dfs(v, u)
                low[u] = min(low[u], low[v])
                if low[v] > disc[u]:
                    bridges.append(tuple(sorted((u, v))))
            elif v != parent:
                low[u] = min(low[u], disc[v])

    for i in range(n):
        if disc[i] == -1:
            dfs(i, -1)

    return {
        'components': len(components),
        'sizes': sizes,
        'is_bipartite': is_bipartite,
        'bridges': sorted(bridges),
    }

import heapq

class MedianFinder:
    def __init__(self):
        self.lo = []  # max-heap (negated)
        self.hi = []  # min-heap
        self.lo_del = {}
        self.hi_del = {}
        self.lo_size = 0
        self.hi_size = 0

    def add(self, num):
        if not self.lo or num <= -self.lo[0]:
            heapq.heappush(self.lo, -num)
            self.lo_size += 1
        else:
            heapq.heappush(self.hi, num)
            self.hi_size += 1
        self._balance()

    def _balance(self):
        while self.lo_size > self.hi_size + 1:
            val = -heapq.heappop(self.lo)
            self.lo_size -= 1
            while self.lo and (-self.lo[0]) in self.lo_del and self.lo_del[-self.lo[0]] > 0:
                d = -heapq.heappop(self.lo)
                self.lo_del[d] -= 1
                self.lo_size -= 1
            heapq.heappush(self.hi, val)
            self.hi_size += 1
        while self.hi_size > self.lo_size:
            val = heapq.heappop(self.hi)
            self.hi_size -= 1
            while self.hi and self.hi[0] in self.hi_del and self.hi_del[self.hi[0]] > 0:
                d = heapq.heappop(self.hi)
                self.hi_del[d] -= 1
                self.hi_size -= 1
            heapq.heappush(self.lo, -val)
            self.lo_size += 1

    def _clean_top(self):
        while self.lo and (-self.lo[0]) in self.lo_del and self.lo_del[-self.lo[0]] > 0:
            d = -heapq.heappop(self.lo)
            self.lo_del[d] -= 1
        while self.hi and self.hi[0] in self.hi_del and self.hi_del[self.hi[0]] > 0:
            d = heapq.heappop(self.hi)
            self.hi_del[d] -= 1

    def median(self):
        self._clean_top()
        if self.lo_size == self.hi_size:
            return (-self.lo[0] + self.hi[0]) / 2.0
        return float(-self.lo[0])

    def count(self):
        return self.lo_size + self.hi_size

    def remove(self, num):
        if not self.lo and not self.hi:
            return False
        self._clean_top()
        if self.lo and num <= -self.lo[0]:
            self.lo_del[num] = self.lo_del.get(num, 0) + 1
            self.lo_size -= 1
        elif self.hi:
            self.hi_del[num] = self.hi_del.get(num, 0) + 1
            self.hi_size -= 1
        else:
            return False
        self._balance()
        return True

class MinMaxStack:
    def __init__(self):
        self._stack = []
        self._mins = []
        self._maxs = []

    def push(self, val):
        self._stack.append(val)
        self._mins.append(val if not self._mins else min(val, self._mins[-1]))
        self._maxs.append(val if not self._maxs else max(val, self._maxs[-1]))

    def pop(self):
        if not self._stack:
            raise IndexError("pop from empty stack")
        self._mins.pop()
        self._maxs.pop()
        return self._stack.pop()

    def peek(self):
        if not self._stack:
            raise IndexError("peek from empty stack")
        return self._stack[-1]

    def min(self):
        if not self._mins:
            raise IndexError("min from empty stack")
        return self._mins[-1]

    def max(self):
        if not self._maxs:
            raise IndexError("max from empty stack")
        return self._maxs[-1]

    def size(self):
        return len(self._stack)

    def is_empty(self):
        return len(self._stack) == 0

