class CircularDeque:
    def __init__(self, capacity):
        self.cap = capacity
        self.buf = [None] * capacity
        self.head = 0
        self.tail = 0
        self._size = 0

    def push_front(self, val):
        if self._size == self.cap:
            return False
        self.head = (self.head - 1) % self.cap
        self.buf[self.head] = val
        self._size += 1
        return True

    def push_back(self, val):
        if self._size == self.cap:
            return False
        self.buf[self.tail] = val
        self.tail = (self.tail + 1) % self.cap
        self._size += 1
        return True

    def pop_front(self):
        if self._size == 0:
            raise IndexError("pop from empty deque")
        val = self.buf[self.head]
        self.head = (self.head + 1) % self.cap
        self._size -= 1
        return val

    def pop_back(self):
        if self._size == 0:
            raise IndexError("pop from empty deque")
        self.tail = (self.tail - 1) % self.cap
        val = self.buf[self.tail]
        self._size -= 1
        return val

    def front(self):
        if self._size == 0:
            raise IndexError("front from empty deque")
        return self.buf[self.head]

    def back(self):
        if self._size == 0:
            raise IndexError("back from empty deque")
        return self.buf[(self.tail - 1) % self.cap]

    def is_full(self):
        return self._size == self.cap

    def is_empty(self):
        return self._size == 0

    def size(self):
        return self._size

    def to_list(self):
        result = []
        for i in range(self._size):
            result.append(self.buf[(self.head + i) % self.cap])
        return result

