def parse_url(url):
    url = url.strip()
    if '://' not in url:
        raise ValueError(f"Invalid URL: no scheme in '{url}'")
    scheme, rest = url.split('://', 1)
    scheme = scheme.lower()
    fragment = ''
    if '#' in rest:
        rest, fragment = rest.rsplit('#', 1)
    query = {}
    if '?' in rest:
        rest, query_str = rest.split('?', 1)
        for pair in query_str.split('&'):
            if '=' in pair:
                k, v = pair.split('=', 1)
                query[k] = v
            elif pair:
                query[pair] = ''
    path = ''
    if '/' in rest:
        idx = rest.index('/')
        host_port = rest[:idx]
        path = rest[idx:]
    else:
        host_port = rest
        path = '/'
    port = None
    if ':' in host_port:
        host, port_str = host_port.rsplit(':', 1)
        try:
            port = int(port_str)
        except ValueError:
            host = host_port
            port = None
    else:
        host = host_port
    default_ports = {'http': 80, 'https': 443, 'ftp': 21}
    if port is None:
        port = default_ports.get(scheme)
    return {
        'scheme': scheme,
        'host': host,
        'port': port,
        'path': path,
        'query': query,
        'fragment': fragment,
    }

