        raise ValueError("No separator row found")
    result = []
    for line in lines[2:]:
        cells = parse_row(line)
        row = {}
        for i, h in enumerate(headers):
            row[h] = cells[i] if i < len(cells) else ''
        result.append(row)
    return result

