class StateMachine:
    def __init__(self, initial_state):
        self._initial = initial_state
        self._state = initial_state
        self._transitions = {}
        self._history = []

    def add_transition(self, from_state, event, to_state, action=None):
        self._transitions[(from_state, event)] = (to_state, action)

    def trigger(self, event):
        key = (self._state, event)
        if key not in self._transitions:
            raise ValueError(f"No transition from '{self._state}' on event '{event}'")
        to_state, action = self._transitions[key]
        from_state = self._state
        self._state = to_state
        self._history.append((from_state, event, to_state))
        if action is not None:
            action()
        return self._state

    @property
    def state(self):
        return self._state

    @property
    def history(self):
        return list(self._history)

    def reset(self):
        self._state = self._initial
        self._history.clear()

    def can_trigger(self, event):
        return (self._state, event) in self._transitions

