    def _delete(self, node, word, i):
        if i == len(word):
            if '_freq' in node:
                del node['_freq']
                self._count -= 1
                return True
            return False
        ch = word[i]
        if ch not in node:
            return False
        result = self._delete(node[ch], word, i + 1)
        if not node[ch]:
            del node[ch]
        return result

    def count(self):
        return self._count

    def prefix_count(self, prefix):
        node = self.root
        for ch in prefix:
            if ch not in node:
                return 0
            node = node[ch]
        return self._count_under(node)

    def _count_under(self, node):
        c = 1 if '_freq' in node else 0
        for ch in node:
            if ch != '_freq':
                c += self._count_under(node[ch])
        return c

def deep_copy(obj, memo=None):
    if memo is None:
        memo = {}
    obj_id = id(obj)
    if obj_id in memo:
        return memo[obj_id]
    if isinstance(obj, (int, float, str, bool, type(None))):
        return obj
    if isinstance(obj, dict):
        result = {}
        memo[obj_id] = result
        for k, v in obj.items():
            result[deep_copy(k, memo)] = deep_copy(v, memo)
        return result
    if isinstance(obj, list):
        result = []
        memo[obj_id] = result
        for item in obj:
            result.append(deep_copy(item, memo))
        return result
    if isinstance(obj, tuple):
        # Can't pre-register since tuples are immutable
        result = tuple(deep_copy(item, memo) for item in obj)
        memo[obj_id] = result
        return result
    if isinstance(obj, set):
        result = set()
        memo[obj_id] = result
        for item in obj:
            result.add(deep_copy(item, memo))
        return result
    return obj
